class Film:

  def __init__(self, namn, utgivningsår, kommentatorspår = False):
    self.titel = namn
    self.utgivningsår = utgivningsår
    self.kommentatorspår = kommentatorspår

  def __str__(self):
    if self.kommentatorspår == False:
      sträng = " har inte kommentatorspår."
    else:
      sträng = " har kommentatorspår."
    return self.titel + "gavs ut " + str(self.utgivningsår) + sträng

  def lägg_till_kommentatorspår(self):
    self.kommentatorspår = True

film = Film("Nyckeln till frihet", 1994, False)
filmer= [Film("Gudfadern",1972, False), Film("Titanic",1997,False), film]
film.lägg_till_kommentatorspår()

for element in filmer:
  print(element)
